import{_ as e,o as i,c as t,Q as n}from"./chunks/framework.b67c47e6.js";const m=JSON.parse('{"title":"Mobi One","description":"","frontmatter":{},"headers":[],"relativePath":"guide/machine_files/machines/mobi_one/index.md","filePath":"guide/machine_files/machines/mobi_one/index.md","lastUpdated":1773939149000}'),o={name:"guide/machine_files/machines/mobi_one/index.md"},r=n('<h1 id="mobi-one" tabindex="-1">Mobi One <a class="header-anchor" href="#mobi-one" aria-label="Permalink to &quot;Mobi One&quot;">​</a></h1><p>The Mobi One (by H&amp;M) is an automated timber wall panel processing machine. It handles the entire panel manufacturing process — framing, nailing, milling, sawing, drilling, and gluing — in a single station.</p><nav class="table-of-contents"><ul><li><a href="#overview">Overview</a></li><li><a href="#processing-units">Processing Units</a></li><li><a href="#configuration-in-produuz-it">Configuration in Produuz.it</a><ul><li><a href="#machine-setup">Machine Setup</a></li><li><a href="#job-settings">Job Settings</a></li></ul></li><li><a href="#generating-machine-files">Generating Machine Files</a></li><li><a href="#linking-to-production">Linking to Production</a></li></ul></nav><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Mobi One is set up as a <strong>machine</strong> linked to a <strong>station</strong> in your production line. When a constructible reaches that station, the system can generate MOB machine files with all the manufacturing instructions.</p><p>There are two versions:</p><ul><li><strong>Mobi One V1</strong> — Single-carriage design, generates MOB v1 files.</li><li><strong>Mobi One V2</strong> — Dual-carriage design with expanded capabilities, generates MOB v2 files.</li></ul><h2 id="processing-units" tabindex="-1">Processing Units <a class="header-anchor" href="#processing-units" aria-label="Permalink to &quot;Processing Units&quot;">​</a></h2><p>The Mobi One can be equipped with various processing units depending on your configuration:</p><table><thead><tr><th>Unit</th><th>Function</th></tr></thead><tbody><tr><td><strong>Framing</strong></td><td>Processes frame members (studs, top/bottom plates)</td></tr><tr><td><strong>Nailers</strong></td><td>High-speed pneumatic nailers for fastening cladding and battens</td></tr><tr><td><strong>Screwers</strong></td><td>Mechanical screw drivers</td></tr><tr><td><strong>Miller/Router</strong></td><td>Spindle for routing openings, cutouts, and milling operations</td></tr><tr><td><strong>Drill</strong></td><td>Multi-spindle or single-head drilling</td></tr><tr><td><strong>Saw</strong></td><td>Cross-cutting blade for transverse cuts</td></tr><tr><td><strong>Gluing</strong></td><td>Adhesive application system</td></tr></tbody></table><h2 id="configuration-in-produuz-it" tabindex="-1">Configuration in Produuz.it <a class="header-anchor" href="#configuration-in-produuz-it" aria-label="Permalink to &quot;Configuration in Produuz.it&quot;">​</a></h2><h3 id="machine-setup" tabindex="-1">Machine Setup <a class="header-anchor" href="#machine-setup" aria-label="Permalink to &quot;Machine Setup&quot;">​</a></h3><p>In <strong>Company Settings &gt; Production Lines</strong>, configure the Mobi One with:</p><ul><li><strong>Layer orientation</strong> — Inside, outside, or none.</li><li><strong>X-axis mirroring</strong> — Mirror operations along the X-axis if needed.</li><li><strong>Machine zero position</strong> — The reference point for the coordinate system (top-right, top-left, bottom-right, or bottom-left).</li><li><strong>Nailing matrix</strong> — Customize nail patterns by beam size.</li><li><strong>Processing thresholds</strong> — Minimum mill radius, CTC distances, and other tolerances.</li></ul><h3 id="job-settings" tabindex="-1">Job Settings <a class="header-anchor" href="#job-settings" aria-label="Permalink to &quot;Job Settings&quot;">​</a></h3><p>When generating machine files, configure per-job options:</p><ul><li><strong>Starting side</strong> — Which face to begin processing (inside or outside).</li><li><strong>Shift mode</strong> — How operations are shifted between layers.</li><li><strong>Nailing pattern</strong> — Regular, large panel, or optimized.</li><li><strong>Mill direction</strong> — Clockwise or counter-clockwise per zone.</li><li><strong>Tool assignments</strong> — Which physical unit to use for each zone.</li><li><strong>CTC spacing</strong> — Center-to-center distances for nail lines.</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Job settings can be saved as defaults on the machine setup, so you don&#39;t have to configure them each time you generate files.</p></div><h2 id="generating-machine-files" tabindex="-1">Generating Machine Files <a class="header-anchor" href="#generating-machine-files" aria-label="Permalink to &quot;Generating Machine Files&quot;">​</a></h2><ol><li>Go to the <strong>Reports</strong> tab in your project.</li><li>Click <strong>New Report</strong> and select <strong>MOB v1 Machine File</strong> (or MOB v2).</li><li>Select the assemblies to process.</li><li>Choose the production line and machine.</li><li>Adjust job settings if needed.</li><li>Click <strong>Submit</strong> to generate.</li></ol><p>The output is a ZIP file containing one <code>.mob</code> file per assembly.</p><h2 id="linking-to-production" tabindex="-1">Linking to Production <a class="header-anchor" href="#linking-to-production" aria-label="Permalink to &quot;Linking to Production&quot;">​</a></h2><p>When the Mobi One station is configured in your production line, the machine files are available to production workers through the <a href="/guide/viewer/">Viewer</a>. The operations drawings button shows the machine processing sequence for each constructible.</p>',23),a=[r];function s(l,c,g,d,h,u){return i(),t("div",null,a)}const f=e(o,[["render",s]]);export{m as __pageData,f as default};
